<?php require __DIR__.'/../includes/bootstrap.php';require_auth();if(!booths_schema_ready())redirect('upgrade-booths-marketplace.php');$u=user();$companies=companies_schema_ready()?manageable_companies((int)$u['id']):[];$brands=[];if(brands_schema_ready()){$s=db()->prepare("SELECT b.* FROM brands b LEFT JOIN brand_members bm ON bm.brand_id=b.id WHERE b.status='approved' AND (b.submitted_by=? OR bm.user_id=? OR ?='admin') GROUP BY b.id ORDER BY b.name");$s->execute([$u['id'],$u['id'],$u['role']]);$brands=$s->fetchAll();}$universes=universe_engine_ready()?db()->query("SELECT id,name FROM universes WHERE status='approved' AND is_active=1 ORDER BY name")->fetchAll():[];
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$name=trim($_POST['name']??'');if($name===''){flash('error','Booth name is required.');}else{try{$stmt=db()->prepare("INSERT INTO booths(owner_user_id,company_id,brand_id,name,slug,tagline,description,website,contact_email,commerce_mode,external_store_url,status) VALUES(?,?,?,?,?,?,?,?,?,?,?,'pending')");$company=(int)($_POST['company_id']??0)?:null;$brand=(int)($_POST['brand_id']??0)?:null;$stmt->execute([$u['id'],$company,$brand,$name,booth_slug($name),trim($_POST['tagline']??''),trim($_POST['description']??''),trim($_POST['website']??''),trim($_POST['contact_email']??$u['email']),$_POST['commerce_mode']??'demo',trim($_POST['external_store_url']??'')]);$id=(int)db()->lastInsertId();$logo=save_booth_image('logo','logos',$id);$banner=save_booth_image('banner','banners',$id);if($logo||$banner){db()->prepare('UPDATE booths SET logo_path=COALESCE(?,logo_path),banner_path=COALESCE(?,banner_path) WHERE id=?')->execute([$logo,$banner,$id]);}$ins=db()->prepare('INSERT IGNORE INTO booth_universes(booth_id,universe_id) VALUES(?,?)');foreach($_POST['universe_ids']??[] as $uid)$ins->execute([$id,(int)$uid]);flash('success','Your booth was submitted for administrator approval.');redirect('booth/dashboard.php');}catch(Throwable $e){flash('error',$e->getMessage());}}}
app_header('Open a Booth');?>
<section class="form-card"><p class="eyebrow">EXHIBITOR APPLICATION</p><h1>Open a Convention Booth</h1><p>Your booth combines a public profile, product table, and future event/community features.</p><form method="post" enctype="multipart/form-data" class="form-grid"><?=csrf_field()?><label>Booth name<input name="name" required></label><label>Tagline<input name="tagline" maxlength="255"></label><label class="full">Description<textarea name="description" rows="6"></textarea></label><label>Company<select name="company_id"><option value="">Independent / none</option><?php foreach($companies as $c):?><option value="<?=$c['id']?>"><?=e($c['name'])?></option><?php endforeach?></select></label><label>Brand<select name="brand_id"><option value="">No brand</option><?php foreach($brands as $b):?><option value="<?=$b['id']?>"><?=e($b['name'])?></option><?php endforeach?></select></label><label>Website<input type="url" name="website"></label><label>Contact email<input type="email" name="contact_email" value="<?=e($u['email'])?>"></label><label>Commerce mode<select name="commerce_mode"><option value="demo">Geek Nation demo checkout</option><option value="external">External store link</option><option value="disabled">Display only</option></select></label><label>External store URL<input type="url" name="external_store_url"></label><label>Logo<input type="file" name="logo" accept="image/*"></label><label>Banner<input type="file" name="banner" accept="image/*"></label><?php if($universes):?><fieldset class="full"><legend>Universes</legend><div class="checkbox-grid"><?php foreach($universes as $x):?><label><input type="checkbox" name="universe_ids[]" value="<?=$x['id']?>"> <?=e($x['name'])?></label><?php endforeach?></div></fieldset><?php endif?><div class="full"><button class="button primary">Submit Booth</button></div></form></section><?php app_footer();